const fs = require\(''fs''\);
const content = fs.readFileSync\(''lighthouse-reports/staging-performance-test.html'', ''utf8''\);

// 提取关键性能指标
const categories = [''performance'', ''accessibility'', ''best-practices'', ''seo''];
const results = {};

categories.forEach\(cat => {
  const regex = new RegExp\(''""'' + cat + ''"":\\{""score"":\([0-9.]+\)\\}''\);
  const match = content.match\(regex\);
  if \(match\) {
    results[cat] = Math.round\(parseFloat\(match[1]\) * 100\);
  }
}\);

console.log\(''=== Performance Test Results ===''\);
Object.entries\(results\).forEach\(\([key, value]\) => {
  const status = value >= 90 ? ''✅ Excellent'' : value >= 75 ? ''⚠️ Good'' : ''❌ Needs Work'';
  console.log\(key + '':'', value + ''/100'', status\);
}\);

// 检查是否有改进建议
const audits = content.match\(/""id"":"".*?"",""title"":"".*?"",""description"":"".*?"",""score"":\([0-9.]+\)/g\) || [];
const failedAudits = audits.filter\(audit => {
  const score = parseFloat\(audit.match\(/""score"":\([0-9.]+\)/\)![1]\);
  return score < 0.9;
}\);

console.log\(''\\n=== Key Issues Found ===''\);
failedAudits.slice\(0, 5\).forEach\(audit => {
  const title = audit.match\(/""title"":""\([^""]+\)""/\)?.[1];
  console.log\(''-'', title\);
}\);
")

