  try {
    await client.connect\(\);

    // 先检查是否有admin用户
    const existResult = await client.query\(''SELECT id FROM users WHERE feishuId = \\$1'', [''admin'']\);

    if \(existResult.rows.length === 0\) {
      // 创建一个admin用户
