      await client.query\(
        ''INSERT INTO tenants \(id, name, code, createdAt, updatedAt\) VALUES \(\\$1, \\$2, \\$3, NOW\(\), NOW\(\)\) ON CONFLICT \(id\) DO NOTHING'',
        [tenantId, ''Default'', ''default'']
      \);

      // 创建admin用户
      await client.query\(
        ''INSERT INTO users \(id, feishuId, name, role, tenantId, createdAt, updatedAt\) VALUES \(\\$1, \\$2, \\$3, \\$4, \\$5, NOW\(\), NOW\(\)\)'',
        [userId, ''admin'', ''Admin User'', ''admin'', tenantId]
      \);

      await client.query\(''COMMIT''\);

      console.log\(''Created admin user:''\);
      console.log\(''  User ID:'', userId\);
      console.log\(''  Tenant ID:'', tenantId\);
      console.log\(''  Feishu ID: admin''\);
