      console.log\(''Admin user already exists with ID:'', existResult.rows[0].id\);
    }

  } catch \(error\) {
    await client.query\(''ROLLBACK''\);
    console.error\(''Error:'', error\);
  } finally {
    await client.end\(\);
  }
