    console.log\(''\\nMigrating tenants table...''\);
    try {
      await client.query\(''ALTER TABLE tenants ADD COLUMN IF NOT EXISTS isActive boolean DEFAULT true''\);
      console.log\(''✓ Added isActive column to tenants''\);
    } catch \(e\) {
      console.log\(''isActive column might already exist''\);
    }

