      await client.query\(''ALTER TABLE tenants ADD COLUMN IF NOT EXISTS settings jsonb DEFAULT \\''{}\\\\''''\);
      console.log\(''✓ Added settings column to tenants''\);
    } catch \(e\) {
      console.log\(''settings column might already exist''\);
    }

    // 创建默认租户
    console.log\(''\\nCreating default tenant...''\);
    const tenantId = ''def00000-0000-0000-0000-000000000001'';
    await client.query\(\\`
      INSERT INTO tenants \(id, name, slug, isActive, settings, createdAt, updatedAt\) 
      VALUES \($1, $2, $3, $4, $5, NOW\(\), NOW\(\)\) 
      ON CONFLICT \(id\) DO UPDATE SET
        name = EXCLUDED.name,
        slug = EXCLUDED.slug,
        updatedAt = NOW\(\)
    \\`, [tenantId, ''Default'', ''default'', true, ''{}'']\);

    console.log\(''✓ Default tenant created with ID:'', tenantId\);

    // 创建或更新 admin 用户
    console.log\(''\\nCreating admin user...''\);
    const { v4: uuidv4 } = require\(''uuid''\);

    // 先检查是否已存在
    const existResult = await client.query\(''SELECT id FROM users WHERE feishuId = $1'', [''admin'']\);

    if \(existResult.rows.length === 0\) {
      const userId = uuidv4\(\);
      await client.query\(\\`
        INSERT INTO users \(id, feishuId, name, role, tenantId, isActive, createdAt, updatedAt\) 
        VALUES \($1, $2, $3, $4, $5, $6, NOW\(\), NOW\(\)\)
      \\`, [userId, ''admin'', ''Admin User'', ''ADMIN'', tenantId, true]\);

      console.log\(''✓ Created admin user with ID:'', userId\);
    } else {
      await client.query\(\\`
        UPDATE users 
        SET 
          name = ''Admin User'',
          role = ''ADMIN'',
          tenantId = $1,
          isActive = true,
          updatedAt = NOW\(\)
        WHERE feishuId = ''admin''
      \\`, [tenantId]\);

      console.log\(''✓ Updated admin user''\);
    }

    console.log\(''\\nMigration completed successfully!''\);

  } catch \(error\) {
    console.error\(''Migration error:'', error\);
  } finally {
    await client.end\(\);
  }
}

runMigrations\(\);
")

